class Solution:
    def pivotArray(self, nums: List[int], pivot: int) -> List[int]:
        less, equal, greater = [], [], []
        for v in nums:
            if v < pivot:
                less.append(v)
            elif v > pivot:
                greater.append(v)
            else:
                equal.append(v)
        return less + equal + greater

